What does this program print?

```cpp
#include <iostream>

enum class Planet { mercury, venus, earth, mars };

std::ostream& operator<<(std::ostream& out, Planet p)
{
    switch (p)
    {
        case Planet::mercury: out << "Mercury"; break;
        case Planet::venus:   out << "Venus";   break;
        case Planet::earth:   out << "Earth";   break;
        case Planet::mars:    out << "Mars";    break;
    }
    return out;
}

int main()
{
    Planet p{ Planet::earth };
    std::cout << p << '\n';
    std::cout << static_cast<int>(p) << '\n';
    return 0;
}
```

